package com.izonehub.stores.auth;import com.izonehub.stores.user.AppUser;import io.jsonwebtoken.Jwts;import io.jsonwebtoken.security.Keys;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import javax.crypto.SecretKey;import java.nio.charset.StandardCharsets;import java.time.Instant;import java.util.Date;
@Service public class JwtService{private final SecretKey key;private final String issuer;private final long minutes;public JwtService(@Value("${app.jwt.secret}")String secret,@Value("${app.jwt.issuer}")String issuer,@Value("${app.jwt.access-token-minutes}")long minutes){this.key=Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));this.issuer=issuer;this.minutes=minutes;} public String issueAccessToken(AppUser u){Instant now=Instant.now();return Jwts.builder().issuer(issuer).subject(u.getEmail()).claim("role",u.getRole().name()).issuedAt(Date.from(now)).expiration(Date.from(now.plusSeconds(minutes*60))).signWith(key).compact();}}
